import{_ as a,c as r,o,ag as e}from"./chunks/framework.XjE0kKti.js";const b=JSON.parse('{"title":"系统监控","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0000.md","filePath":"modules/hub0000.md","lastUpdated":null}'),d={name:"modules/hub0000.md"};function n(h,t,s,l,i,c){return o(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="系统监控" tabindex="-1">系统监控 <a class="header-anchor" href="#系统监控" aria-label="Permalink to &quot;系统监控&quot;">​</a></h1><p>在网关控制台中集中查看<strong>已纳入监控的服务器</strong>运行状况：先选定目标机器，再阅读身份信息与多组时序指标，用于日常巡检、容量评估与异常定位。</p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p><strong>系统监控</strong>面向运维与网关管理员，回答三类问题：</p><ol><li><strong>这是哪台机器</strong>——主机名、操作系统、架构、部署形态与访问地址。</li><li><strong>资源是否健康</strong>——CPU、内存、磁盘、磁盘 IO、网络在一段时间内是否平稳、是否逼近容量上限。</li><li><strong>是否需要跟进</strong>——结合页面上的预警区间、图例与空状态提示，判断是否要扩容、查日志或联系后端/采集侧。</li></ol><p>登录后通常可从侧栏首项进入本页（具体菜单以当前环境为准）。</p><hr><h2 id="使用流程" tabindex="-1">使用流程 <a class="header-anchor" href="#使用流程" aria-label="Permalink to &quot;使用流程&quot;">​</a></h2><h3 id="_1-选择监控目标" tabindex="-1">1. 选择监控目标 <a class="header-anchor" href="#_1-选择监控目标" aria-label="Permalink to &quot;1. 选择监控目标&quot;">​</a></h3><p>在页面顶部的 <strong>服务器选择</strong> 中，从下拉列表指定一台<strong>监控服务器</strong>。列表由服务端根据权限与采集配置下发；若列表为空或长期无法加载，需要在网关或监控侧确认节点是否已注册、采集是否正常、当前账号是否有查看权限。</p><h3 id="_2-刷新数据" tabindex="-1">2. 刷新数据 <a class="header-anchor" href="#_2-刷新数据" aria-label="Permalink to &quot;2. 刷新数据&quot;">​</a></h3><p>在已选择服务器的前提下，使用 <strong>刷新数据</strong> 可重新请求当前视图依赖的数据（各图表上的「刷新」则只作用于该图表）。首次进入或切换服务器后，若出现加载动画，请等待结束后再读数。</p><h3 id="_3-阅读指标" tabindex="-1">3. 阅读指标 <a class="header-anchor" href="#_3-阅读指标" aria-label="Permalink to &quot;3. 阅读指标&quot;">​</a></h3><p>下方按区域展示多组图表；每一块均可调整<strong>时间范围</strong>并单独刷新（控件布局以当前版本界面为准）。建议先看 <strong>CPU / 内存</strong>，再看 <strong>磁盘与磁盘 IO</strong>，最后看 <strong>网络</strong> 与 <strong>进程</strong> 类视图，以便从「计算 → 存储 → 网络」逐层缩小范围。</p><hr><h2 id="服务器信息" tabindex="-1">服务器信息 <a class="header-anchor" href="#服务器信息" aria-label="Permalink to &quot;服务器信息&quot;">​</a></h2><p>选定服务器后，<strong>服务器信息</strong>区域展示该实例的静态概要，便于确认「当前曲线对应的是哪台机器」。常见项包括：</p><table tabindex="0"><thead><tr><th>信息项</th><th>用途</th></tr></thead><tbody><tr><td>主机名</td><td>在资产与日志中定位该节点。</td></tr><tr><td>操作系统</td><td>区分 Windows、Linux、macOS 等大类。</td></tr><tr><td>系统版本</td><td>核对内核或发行版版本；过长时可悬停查看全文。</td></tr><tr><td>系统架构</td><td>如 x86_64，用于与软件包、镜像架构对齐。</td></tr><tr><td>服务器类型</td><td>物理机、虚拟机等归类，便于与容量规划策略对应。</td></tr><tr><td>IP 地址</td><td>与网络策略、白名单及上下游连通性排查相关。</td></tr></tbody></table><hr><h2 id="指标说明" tabindex="-1">指标说明 <a class="header-anchor" href="#指标说明" aria-label="Permalink to &quot;指标说明&quot;">​</a></h2><h3 id="cpu-与内存" tabindex="-1">CPU 与内存 <a class="header-anchor" href="#cpu-与内存" aria-label="Permalink to &quot;CPU 与内存&quot;">​</a></h3><p>以<strong>使用率随时间变化</strong>为主；页面为使用率配置了<strong>预警区间</strong>（偏高与过高两档，以图例与曲线配色为准），便于快速发现持续打满或尖峰。若业务低峰期仍长期贴近上限，通常需要评估算力或排查异常进程。</p><h3 id="磁盘与磁盘-io" tabindex="-1">磁盘与磁盘 IO <a class="header-anchor" href="#磁盘与磁盘-io" aria-label="Permalink to &quot;磁盘与磁盘 IO&quot;">​</a></h3><p><strong>磁盘</strong>侧重空间占用趋势，<strong>磁盘 IO</strong> 侧重读写吞吐或 IOPS 类趋势。磁盘打满会导致写入失败与连锁故障；IO 长期冲高可能意味着慢查询、批量任务或大文件读写，需要结合业务窗口判断。</p><h3 id="网络流量" tabindex="-1">网络流量 <a class="header-anchor" href="#网络流量" aria-label="Permalink to &quot;网络流量&quot;">​</a></h3><p>区分上行与下行（或收发）方向，用颜色区分趋势，便于判断是否为突发流量、备份窗口或异常外联。若与其它指标同时异常，可优先排查网络策略与上游依赖。</p><h3 id="进程" tabindex="-1">进程 <a class="header-anchor" href="#进程" aria-label="Permalink to &quot;进程&quot;">​</a></h3><p>汇总与进程相关的监控信息，用于在主机层面观察<strong>是否有异常占用</strong>或与网关进程相关的波动；具体指标名称以界面为准。</p><hr><h2 id="空状态与排查" tabindex="-1">空状态与排查 <a class="header-anchor" href="#空状态与排查" aria-label="Permalink to &quot;空状态与排查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>提示</th><th>含义与建议</th></tr></thead><tbody><tr><td>请选择一个服务器查看监控数据</td><td>列表有数据但未选择；先在顶部下拉框选定目标。</td></tr><tr><td>暂无可用的服务器</td><td>当前租户或账号下没有可监控节点；由管理员配置采集目标或授权。</td></tr><tr><td>正在加载服务器监控数据</td><td>数据拉取中；若长时间不结束，检查网络、网关服务与监控数据源。</td></tr></tbody></table><p>若各图表长期无数据或数值明显不可信，在排除浏览器缓存与本地网络后，请通过运维渠道核对：采集代理是否在线、指标上报周期、以及网关与监控服务之间的连通性。</p><hr><h2 id="更多信息" tabindex="-1">更多信息 <a class="header-anchor" href="#更多信息" aria-label="Permalink to &quot;更多信息&quot;">​</a></h2><p>部署架构、接口约定与监控数据模型等<strong>开发与运维文档</strong>见仓库内说明；本页仅描述控制台中的操作与读数方式。</p>',36)])])}const g=a(d,[["render",n]]);export{b as __pageData,g as default};
